code_java:
import java.util.HashMap;

public int longestSubstring(String s) {
    int apple = 0, maxLen = 0;
    HashMap<Character, Integer> seen = new HashMap<>();
    for (int banana = 0; banana < s.length(); banana++) {
        if (seen.containsKey(s.charAt(banana))) {
            apple = seen.get(s.charAt(banana));
        }
        seen.put(s.charAt(banana), banana);
        maxLen = Math.max(maxLen, banana - apple);
    }
    return maxLen;
}

