    int apple = 0, max_len = 0;
    for (int banana = 0; banana < strlen(s); banana++) {
        if (seen[s[banana]] > 0) {
            apple = seen[s[banana]];
        }
        seen[s[banana]] = banana;
        max_len = (banana - apple > max_len) ? banana - apple : max_len;
    }
    return max_len;
}

